import React from "react";

const HeroServices = () => {
  return (
    <div className="w-full h-auto mx-auto flex flex-col justify-start items-center">
      <h1 className="text-[170px] text-center font-black uppercase tracking-widest bg-gradient-to-b from-white/15 to-transparent bg-clip-text text-transparent">
        Our Services
      </h1>
      <div className="center-box">
        <div className="border-mask">
          <div className="animated-border-box-glow"></div>
          <div className="animated-border-box">
            <span className="text-white text-[18px] font-medium px-6 py-2">
              Case Studies
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HeroServices;
